import { useCallback, useEffect, useSyncExternalStore } from "react";
import { getBuiltInTheme, type ThemeColors } from "@t3tools/shared/theme";

type Theme = "light" | "dark" | "system";
type ThemeSnapshot = {
  theme: Theme;
  systemDark: boolean;
  paletteThemeId: string | null;
};

const STORAGE_KEY = "t3code:theme";
const PALETTE_STORAGE_KEY = "t3code:palette-theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

/**
 * All CSS custom properties written by the palette theme engine.
 * Stored so they can be cleaned up atomically when reverting to the
 * system light/dark toggle.
 */
const PALETTE_CSS_VARS: readonly string[] = [
  "--background",
  "--foreground",
  "--primary",
  "--primary-foreground",
  "--ring",
  "--sidebar",
  "--sidebar-foreground",
  "--editor",
  "--editor-foreground",
  "--theme-terminal",
  "--theme-terminal-foreground",
  "--status-bar",
  "--status-bar-foreground",
];

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStored(): Theme {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw === "light" || raw === "dark" || raw === "system") return raw;
  return "system";
}

function getStoredPaletteThemeId(): string | null {
  return localStorage.getItem(PALETTE_STORAGE_KEY);
}

/**
 * Apply a palette theme's CSS custom properties to the document root, or
 * clear them all and restore the stored light/dark preference when `null`.
 */
function applyPaletteTheme(themeId: string | null, suppressTransitions = false): void {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  if (themeId === null) {
    // Remove every palette-managed var so the CSS file values take over.
    for (const cssVar of PALETTE_CSS_VARS) {
      document.documentElement.style.removeProperty(cssVar);
    }
    // Restore the stored light/dark/system preference.
    const stored = getStored();
    const isDark = stored === "dark" || (stored === "system" && getSystemDark());
    document.documentElement.classList.toggle("dark", isDark);
  } else {
    const appTheme = getBuiltInTheme(themeId);
    if (!appTheme) return;

    // The palette theme owns the dark/light decision.
    document.documentElement.classList.toggle("dark", appTheme.isDark);

    const c: ThemeColors = appTheme.colors;
    document.documentElement.style.setProperty("--background", c.background);
    document.documentElement.style.setProperty("--foreground", c.foreground);
    document.documentElement.style.setProperty("--primary", c.accent);
    document.documentElement.style.setProperty("--primary-foreground", c.accentForeground);
    document.documentElement.style.setProperty("--ring", c.accent);
    document.documentElement.style.setProperty("--sidebar", c.sidebar);
    document.documentElement.style.setProperty("--sidebar-foreground", c.sidebarForeground);
    document.documentElement.style.setProperty("--editor", c.editor);
    document.documentElement.style.setProperty("--editor-foreground", c.editorForeground);
    document.documentElement.style.setProperty("--theme-terminal", c.terminal);
    document.documentElement.style.setProperty("--theme-terminal-foreground", c.terminalForeground);
    document.documentElement.style.setProperty("--status-bar", c.statusBar);
    document.documentElement.style.setProperty("--status-bar-foreground", c.statusBarForeground);
  }

  if (suppressTransitions) {
    // Force a reflow so no-transitions takes effect before removal.
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

/**
 * Apply the light/dark class to the document root.
 * No-ops when a palette theme is active (the palette owns the dark class).
 */
function applyTheme(theme: Theme, suppressTransitions = false): void {
  if (getStoredPaletteThemeId() !== null) return;

  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  const isDark = theme === "dark" || (theme === "system" && getSystemDark());
  document.documentElement.classList.toggle("dark", isDark);
  if (suppressTransitions) {
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash.
{
  const storedPalette = getStoredPaletteThemeId();
  if (storedPalette !== null) {
    applyPaletteTheme(storedPalette);
  } else {
    applyTheme(getStored());
  }
