    }
    if (theme === "system") return snapshot.systemDark ? "dark" : "light";
    return theme;
  })();

  const setTheme = useCallback((next: Theme) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  const setPaletteThemeId = useCallback((id: string | null) => {
    if (id === null) {
