import type { ReactNode } from "react";
import { useTheme } from "../hooks/useTheme";

interface ThemeProviderProps {
  children?: ReactNode;
}

/**
 * Renders once near the root of the component tree to keep palette-theme CSS
 * custom properties in sync with localStorage across navigation and hot
 * reloads.  All theme state and DOM mutations are managed by the `useTheme`
 * hook — this component is the idiomatic React entry point for that
 * subscription.
 */
export function ThemeProvider({ children }: ThemeProviderProps) {
  // Subscribe to theme changes so React re-renders propagate to the DOM.
  useTheme();
  return <>{children}</>;
}

