import { BUILT_IN_THEMES, type AppTheme, type ThemeColors } from "@t3tools/shared/theme";
import { cn } from "../lib/utils";
import { useTheme } from "../hooks/useTheme";

// ---------------------------------------------------------------------------
// Mini "app window" preview rendered inside each theme card
// ---------------------------------------------------------------------------

interface ThemePreviewProps {
  colors: ThemeColors;
}

function ThemePreview({ colors }: ThemePreviewProps) {
  return (
    <div
      className="h-[3.75rem] w-full overflow-hidden rounded-lg border border-black/10"
      style={{ background: colors.background }}
      aria-hidden="true"
    >
      <div className="flex h-full">
        {/* Sidebar strip */}
        <div
          className="w-5 shrink-0 border-r border-black/10"
          style={{ background: colors.sidebar }}
        >
          {/* Simulated sidebar nav dots */}
          <div className="mt-2 flex flex-col items-center gap-1.5">
            <div
              className="h-1.5 w-1.5 rounded-full opacity-50"
              style={{ background: colors.sidebarForeground }}
            />
            <div
              className="h-1.5 w-1.5 rounded-full opacity-30"
              style={{ background: colors.sidebarForeground }}
            />
            <div
              className="h-1.5 w-1.5 rounded-full opacity-30"
              style={{ background: colors.sidebarForeground }}
            />
          </div>
        </div>

        {/* Main content column */}
        <div className="flex min-w-0 flex-1 flex-col">
          {/* Editor area */}
          <div
            className="flex flex-1 items-start p-1.5"
            style={{ background: colors.editor }}
          >
            {/* Simulated code lines */}
            <div className="flex flex-col gap-1 pt-0.5">
              <div
                className="h-1 w-12 rounded-full opacity-25"
                style={{ background: colors.editorForeground }}
              />
              <div
                className="h-1 w-8 rounded-full opacity-20"
                style={{ background: colors.editorForeground }}
              />
              <div
                className="h-1 w-10 rounded-full opacity-25"
                style={{ background: colors.editorForeground }}
              />
            </div>
            {/* Accent dot — represents active element / cursor */}
            <div className="ml-auto mt-0.5">
              <div
                className="size-2.5 rounded-full opacity-90"
                style={{ background: colors.accent }}
              />
            </div>
          </div>

          {/* Status bar strip */}
          <div
            className="h-2.5 w-full shrink-0"
            style={{ background: colors.statusBar }}
          />
        </div>
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Individual theme card
// ---------------------------------------------------------------------------

interface ThemeCardProps {
  appTheme: AppTheme;
  selected: boolean;
  onSelect: () => void;
}

function ThemeCard({ appTheme, selected, onSelect }: ThemeCardProps) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      aria-label={`Select ${appTheme.label} theme`}
      className={cn(
        "flex flex-col gap-2 rounded-xl border p-2 text-left transition-colors focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-ring",
        selected
          ? "border-primary/60 bg-primary/8"
          : "border-border bg-background hover:bg-accent",
      )}
      onClick={onSelect}
    >
      <ThemePreview colors={appTheme.colors} />

      <div className="flex items-center justify-between gap-1 px-0.5">
        <span
          className={cn(
            "text-xs font-medium",
            selected ? "text-foreground" : "text-muted-foreground",
          )}
        >
          {appTheme.label}
        </span>

        {selected && (
          <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
            Active
          </span>
        )}
      </div>
    </button>
  );
}

// ---------------------------------------------------------------------------
// Public ThemeSelector component
// ---------------------------------------------------------------------------

/**
 * Grid of built-in theme cards with color-swatch previews.  Clicking a card
 * activates that palette theme; clicking an already-active card deselects it
 * (reverting to the system light/dark preference).
 */
export function ThemeSelector() {
  const { paletteThemeId, setPaletteThemeId } = useTheme();

  return (
    <div
      className="grid grid-cols-3 gap-3"
      role="radiogroup"
      aria-label="Color theme"
    >
      {BUILT_IN_THEMES.map((appTheme) => {
        const selected = paletteThemeId === appTheme.id;
        return (
          <ThemeCard
            key={appTheme.id}
            appTheme={appTheme}
            selected={selected}
            // Toggle: click active card to deselect and restore system mode.
            onSelect={() => setPaletteThemeId(selected ? null : appTheme.id)}
          />
        );
      })}
    </div>
  );
}

